import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    adj = [[] for _ in range(n)]
    for u, v, s, e in edges:
        adj[u].append((v, s, e))

    dist = [float('inf')] * n
    dist[0] = 0
    heap = []
    heapq.heappush(heap, (0, 0))

    while heap:
        current_time, u = heapq.heappop(heap)
        if u == n - 1:
            return current_time
        if current_time > dist[u]:
            continue
        for v, s, e in adj[u]:
            if s <= current_time <= e:
                new_time = current_time + 1
                if new_time < dist[v]:
                    dist[v] = new_time
                    heapq.heappush(heap, (new_time, v))
        new_time = current_time + 1
        if new_time < dist[u]:
            dist[u] = new_time
            heapq.heappush(heap, (new_time, u))

    return -1
